body:
These patches add support for the ``` `` ``` token-pasting operator in macros, and clean up whitespace handling (which becomes more important when using ``` `` ```).  I verified with:
```
`define ADD(a,b) a+b
`define CONCAT1(a,b) a``b
`define CONCAT2(a) test_``a
`define CONCAT3(a) a``_test
`define FOO foo
`define BAR bar
`define CONCAT4 `FOO```BAR
`define STRING(a) `"a`"

module test;
   reg r0  = `CONCAT1(foo, bar);
   reg r1  = `CONCAT2(xx);
   reg r2  = `CONCAT3(yy);
   reg r3  = `CONCAT4;
   reg r4  = `ADD(1,2);
   reg r5  = `ADD(1, 2);
   reg r6  = `ADD(1,2 );
   reg r7  = `ADD( 1,2);
   reg r8  = `ADD( 1, 2);
   reg r9  = `ADD( 1,2 );
   reg r10 = `ADD(1 ,2);
   reg r11 = `ADD(1 , 2);
   reg r12 = `ADD(1 ,2 );
   reg r13 = `STRING(hello);
endmodule
```
and compared the output of yosis, iverilog, and Verilog-Perl:
```
yosys -p 'read_verilog -ppdump test.v'
ivlpp test.v # iverilog
vppreproc test.v # Verilog-Perl
```
which all give:
```
module test;
   reg r0  = foobar;
   reg r1  = test_xx;
   reg r2  = yy_test;
   reg r3  = foobar;
   reg r4  = 1+2;
   reg r5  = 1+2;
   reg r6  = 1+2;
   reg r7  = 1+2;
   reg r8  = 1+2;
   reg r9  = 1+2;
   reg r10 = 1+2;
   reg r11 = 1+2;
   reg r12 = 1+2;
   reg r13 = "hello";
endmodule
```
